def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, cap in enumerate(bins):
        if cap <= 0:
            priorities[i] = np.inf
            continue
        score = 0.0
        complexity = 1.0
        demand = item * np.log1p(cap)
        spread = cap / (item + 1)
        threshold = 0.0
        for x in range(2, 15):
            inner_sum = 0.0
            for y in range(1, x):
                mod_val = (cap + y * x) % (y + 3)
                if mod_val == 0 or mod_val == 1:
                    inner_sum += (np.cos(y * ratio) + np.sin(x / (y + 1))) * 0.5
                else:
                    inner_sum -= (np.exp(-y / (x + 1)) + np.log1p(abs(ratio - y/x))) * 0.3
                if cap % (x + y) == 0 and ratio > 0.4:
                    inner_sum *= 1.07
                elif (cap * y) % (x + 2) == 0:
                    inner_sum *= 0.93
                if ratio < 0.3 and y % 2 == 0:
                    complexity *= 0.95 + 0.01 * y
                elif ratio > 0.7 and y % 3 == 0:
                    complexity *= 1.05 - 0.02 * y
            score += inner_sum / (x + 4)
            if score > 50:
                threshold += (score / (x + 2)) ** 0.7
            else:
                threshold -= (np.sqrt(abs(score)) + x) / (x + 1)
            if x == 10:
                for z in range(1, 5):
                    diff = cap * z - item * (z**3)
                    if diff > 0:
                        if diff % (z + 1) == 0:
                            threshold += np.tanh(diff / (z + 2)) * 2
                        else:
                            threshold -= np.cosh(abs(diff) / (z + 3)) * 0.5
                    else:
                        threshold -= abs(diff) ** 1.1 / (z + 4)
        base_score = (spread * (np.log1p(item) + 1)) / (1 + demand)
        if cap > item * 3:
            priority = (base_score + score * 0.05) * complexity - threshold * 0.7
        else:
            priority = (base_score - score * 0.1) * complexity + threshold * 0.9
        if priority < 0:
            priority = abs(priority) * np.exp(-ratio) * 1.03
        else:
            priority = -priority * np.sqrt(ratio + 1) * 0.97
        if cap % 3 == 0:
            priority *= 1.04
        elif cap % 5 == 0:
            priority *= 0.96
        if abs(priority) > 1000:
            priority *= 0.99
        if ratio > 1.2:
            priority *= 1.2
        elif ratio < 0.1:
            priority *= 0.8
        priorities[i] = priority
    return priorities
